import{_ as e,o as i,c as t,aA as s}from"./chunks/framework.JjsrscYF.js";const u=JSON.parse('{"title":"Geospatial Health Informatics Using Census Microdata","description":"","frontmatter":{},"headers":[],"relativePath":"geospatial-intro.md","filePath":"geospatial-intro.md","lastUpdated":null}'),o={name:"geospatial-intro.md"};function n(l,a,r,p,d,c){return i(),t("div",null,[...a[0]||(a[0]=[s(`<h1 id="Geospatial-Health-Informatics-Using-Census-Microdata" tabindex="-1">Geospatial Health Informatics Using Census Microdata <a class="header-anchor" href="#Geospatial-Health-Informatics-Using-Census-Microdata" aria-label="Permalink to &quot;Geospatial Health Informatics Using Census Microdata {#Geospatial-Health-Informatics-Using-Census-Microdata}&quot;">​</a></h1><p>Geospatial health informatics studies health and social outcomes in relation to place. It helps answer questions such as: Which regions have stronger educational attainment? Where are social risk factors concentrated? Which areas should be prioritized for policy action?</p><p>For public health research, this matters because many health patterns are not evenly distributed. Disease burden, healthcare access, education, income, and environmental exposure often vary by region. A map-based workflow makes those differences easier to see, compare, and communicate.</p><p>In this project, we use census microdata together with administrative boundaries to move from individual records to region-level indicators. The example focuses on educational attainment, but the same approach can be reused for many public-health-relevant measures.</p><h2 id="Why-Census-Microdata-Geospatial-Data?" tabindex="-1">Why Census Microdata + Geospatial Data? <a class="header-anchor" href="#Why-Census-Microdata-Geospatial-Data?" aria-label="Permalink to &quot;Why Census Microdata + Geospatial Data? {#Why-Census-Microdata-Geospatial-Data?}&quot;">​</a></h2><ul><li><p>Census microdata provides person-level or household-level variables, which makes it possible to build detailed indicators.</p></li><li><p>IPUMS data projects are designed for integrated population research across time and place, with harmonized documentation and metadata.</p></li><li><p>Geospatial datasets provide the boundary geometry (for example NUTS regions), which turns tabular indicators into maps.</p></li><li><p>When we aggregate microdata by region and join it to boundaries, we can compare population-level trends and detect spatial inequalities.</p></li></ul><p>In practical terms, microdata gives us the &quot;what&quot; and geospatial boundaries give us the &quot;where&quot;. Combining both gives an interpretable view for public health planning and communication.</p><h2 id="IPUMS-in-This-Workflow" tabindex="-1">IPUMS in This Workflow <a class="header-anchor" href="#IPUMS-in-This-Workflow" aria-label="Permalink to &quot;IPUMS in This Workflow {#IPUMS-in-This-Workflow}&quot;">​</a></h2><p>IPUMS (Integrated Public Use Microdata Series) provides structured census and survey data with rich metadata. In this workflow, IPUMS.jl is used to load:</p><ul><li><p>DDI metadata (XML)</p></li><li><p>microdata extract files (DAT)</p></li><li><p>NHGIS-style geospatial files for boundaries</p></li></ul><p>This allows a reproducible, script-first pipeline: load metadata, load records, inspect variables, and then aggregate to region-level outputs for mapping.</p><h2 id="Package-Stack-Used" tabindex="-1">Package Stack Used <a class="header-anchor" href="#Package-Stack-Used" aria-label="Permalink to &quot;Package Stack Used {#Package-Stack-Used}&quot;">​</a></h2><ul><li><code>GeoMakie.jl</code></li></ul><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>Geographic plotting utilities in the Makie ecosystem. Its \`GeoAxis\` supports map projections</span></span>
<span class="line"><span>and coordinate transformations, so data can be displayed in an appropriate destination projection.</span></span></code></pre></div><ul><li><code>CairoMakie.jl</code></li></ul><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>A high-quality Makie backend for SVG/PDF/vector output. This is well-suited for publication-style</span></span>
<span class="line"><span>static figures and clean map exports.</span></span></code></pre></div><ul><li><code>GeoInterfaceMakie.jl</code></li></ul><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>Adds Makie plotting support for geometries that implement GeoInterface traits.</span></span>
<span class="line"><span>In practice, this helps geometry objects from geospatial packages work smoothly with Makie plotting calls.</span></span></code></pre></div><ul><li><code>GeoDataFrames.jl</code></li></ul><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>A DataFrame-oriented way to read and handle geospatial vector data in Julia,</span></span>
<span class="line"><span>inspired by GeoPandas-style workflows.</span></span></code></pre></div><ul><li><code>IPUMS.jl</code></li></ul><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>The package used here to parse DDI metadata and load census and boundary extracts.</span></span>
<span class="line"><span>In this repository environment, IPUMS is pinned from the JuliaHealth IPUMS.jl source in the workflow Manifest.</span></span></code></pre></div><ul><li><code>DataFrames.jl</code>, <code>Chain.jl</code>, <code>StatsBase.jl</code></li></ul><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>Support aggregation, labeling, grouping, and summary steps before visualization.</span></span></code></pre></div><h2 id="End-to-End-Logic" tabindex="-1">End-to-End Logic <a class="header-anchor" href="#End-to-End-Logic" aria-label="Permalink to &quot;End-to-End Logic {#End-to-End-Logic}&quot;">​</a></h2><p>The workflow is intentionally explicit and reproducible:</p><ol><li><p>Acquire census microdata and metadata with IPUMS.jl.</p></li><li><p>Load and clean region boundaries.</p></li><li><p>Assign readable education categories from coded microdata values.</p></li><li><p>Aggregate and normalize counts for fair visual comparison.</p></li><li><p>Join regional summaries to geospatial geometries.</p></li><li><p>Create choropleth maps with clear titles, color schemes, and colorbars.</p></li></ol><p>Each step is documented and implemented as runnable Julia code in the workflow scripts.</p><h2 id="Reproducibility-Note" tabindex="-1">Reproducibility Note <a class="header-anchor" href="#Reproducibility-Note" aria-label="Permalink to &quot;Reproducibility Note {#Reproducibility-Note}&quot;">​</a></h2><p>This example follows a reproducible Poland workflow with explicit file paths, clear transformations, and deterministic plotting steps. If restricted datasets are unavailable, the same structure can be reused with other compatible IPUMS extracts and boundary files.</p>`,30)])])}const m=e(o,[["render",n]]);export{u as __pageData,m as default};
